import React, { useEffect, useState } from "react";
import axios from "axios";

const SERVICE_REGISTRY_URL = "http://http://192.168.2.153:5003/";

const App = () => {
    const [services, setServices] = useState([]);
    const [targetService, setTargetService] = useState("");
    const [response, setResponse] = useState("");

    useEffect(() => {
        const fetchServices = async () => {
            try {
                const res = await axios.get(`${SERVICE_REGISTRY_URL}/services`);
                setServices(Object.keys(res.data));
            } catch (error) {
                console.error("Error fetching services:", error);
            }
        };

        fetchServices();
        const interval = setInterval(fetchServices, 5000);
        return () => clearInterval(interval);
    }, []);

    const sendMessage = async () => {
        if (!targetService) return alert("Select a service to send a message!");

        try {
            const res = await axios.post(`http://${targetService}/receive-message`, {
                message: "Hello from frontend!"
            });
            setResponse(res.data.response);
        } catch (error) {
            setResponse("Failed to send message");
        }
    };

    return (
        <div>
            <h1>Registered Microservices</h1>
            <table border="1">
                <thead>
                    <tr>
                        <th>Service</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    {services.map(service => (
                        <tr key={service}>
                            <td>{service}</td>
                            <td>
                                <button onClick={() => setTargetService(service)}>Select</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
            <br />
            <h2>Send Message</h2>
            <button onClick={sendMessage}>Send Message</button>
            {response && <p><strong>Response:</strong> {response}</p>}
        </div>
    );
};

export default App;
